59	  void resume(const hybrid_state_v1& state)
60	  {
61	    if (state.magic != HYBRID_STATE_MAGIC)
62	      throw std::runtime_error("ResumeDriver::resume: bad magic");
63	    if (state.version != HYBRID_STATE_VERSION)
64	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
65	
66	    // dmactive must transition 0->1 in its own write before any other
67	    // DMCONTROL bit is honored (RISC-V Debug Spec).
68	    bus_.write(kDmcontrol, kDmcontrolDmactive);
69	    request_halt();
70	    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");
71	
72	    // mstatus: enable FS / VS so the following FPR / V abstract writes are
73	    // accepted (FS or VS == Off disables the extension and the hart NACKs
74	    // the writes). Single write covers both extensions when present.
75	    const bool fp_needs_fs = (state.flags & HYBRID_FLAG_FP)
76	                          && (state.mstatus & 0x6000u);  // FS = 13:14
77	    const bool v_needs_vs  = (state.flags & HYBRID_FLAG_V)
78	                          && (state.mstatus & 0x600u);   // VS =  9:10
79	    if (fp_needs_fs || v_needs_vs)
80	      write_csr_abstract_or_pb(kCsrMstatus, state.mstatus);
81	
82	    // FPR restore (requires mstatus.FS enabled above).
83	    if (state.flags & HYBRID_FLAG_FP) {
84	      for (uint16_t i = 0; i < 32; ++i)
85	        write_64bit_register(regno_fpr(i), state.fpr[i]);
86	    }
87	
88	    // Tier-A V CSR restore (before GPRs: PB fallback uses x5 as scratch;
89	    // the GPR loop overwrites x5 afterward so state is preserved).
90	    if (state.flags & HYBRID_FLAG_V) {
91	      // Tier-B: vtype+vl via vsetvl x0,x5,x6 in PB.
92	      // Direct csrrw to vtype sets vill; vl is read-only. Stage operands in
93	      // scratch GPRs x5(vl) and x6(vtype) then let vsetvl set both atomically.
94	      // x5/x6 are overwritten by the GPR loop below, so no leakage.
95	      write_64bit_register(regno_gpr(5), state.vl);
96	      write_64bit_register(regno_gpr(6), state.vtype);
97	      const std::array<uint32_t, 1> pb_vsetvl = { encode_vsetvl(0, 5, 6) };
98	      exec_progbuf(bus_, std::span<const uint32_t>{pb_vsetvl});
99	      // vstart must come AFTER vsetvl: vsetvl resets vstart to 0.
100	      write_csr_abstract_or_pb(kCsrVstart, state.vstart);
101	      write_csr_abstract_or_pb(kCsrVxsat,  state.vxsat);
102	      write_csr_abstract_or_pb(kCsrVxrm,   state.vxrm);
103	      write_csr_abstract_or_pb(kCsrVcsr,   state.vcsr);
104	    }
105	
106	    // GPRs + DPC (after V CSRs so PB scratch x5 is safe to overwrite).
107	    for (uint16_t i = 1; i < 32; ++i)
108	      write_64bit_register(regno_gpr(i), state.gpr[i]);
109	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
110	
111	    write_csr_tolerant(kCsrMtvec, state.mtvec);
112	
113	    // F-T2.4: restore mcycle/minstret so the vsim phase continues counting
114	    // from QEMU1's drain value. Without this, vsim's local counter starts
115	    // at zero and any cycles spent inside the ROI vanish at the QEMU2
116	    // boundary. PB fallback uses x5 as scratch; safe to overwrite here as
117	    // the GPR loop already ran.
118	    write_csr_abstract_or_pb(kCsrMcycle,   state.mcycle);
119	    write_csr_abstract_or_pb(kCsrMinstret, state.minstret);
120	
121	    clear_cmderr_if_set();
122	    request_resume();
123	    poll_until_set(bus_, kDmstatus, kDmstatusAllresumeack,
124	                   "ResumeDriver resume");
125	  }
